from __future__ import annotations


class AgentError(Exception):
    """Root of the project exception hierarchy.

    Raise subclasses; catch this at API boundaries to handle all
    agent failures uniformly.
    """

    def to_dict(self) -> dict:
        """Return a JSON-safe dict for API responses and structured logs."""
        return {
            "error_type": type(self).__name__,
            "message": str(self),
        }


class RecoverableAgentError(AgentError):
    """The agent loop may retry or ask the model to choose another path."""


class FatalAgentError(AgentError):
    """The run cannot continue. Do not retry. Abort the loop."""

