class RateLimitError(RecoverableAgentError):
    """The upstream API enforced a rate limit."""

    def __init__(self, retry_after: float | None = None,
                 provider: str = "") -> None:
        self.retry_after = retry_after
        self.provider = provider
        hint = f" retry after {retry_after}s" if retry_after else ""
        super().__init__(f"{provider} rate limited{hint}".strip())

    def to_dict(self) -> dict:
        return {**super().to_dict(), "retry_after": self.retry_after}


class ToolTimeoutError(RecoverableAgentError):
    """A tool call exceeded its time budget."""

    def __init__(self, tool: str, timeout: float) -> None:
        self.tool = tool
        self.timeout = timeout
        super().__init__(f"{tool} timed out after {timeout}s")

    def to_dict(self) -> dict:
        return {**super().to_dict(), "tool": self.tool, "timeout_s": self.timeout}


class ToolParseError(RecoverableAgentError):
    """The model returned tool arguments that failed schema validation."""

    def __init__(self, tool: str, detail: str, raw: str = "") -> None:
        self.tool = tool
        self.detail = detail
        self._raw = raw          # internal only — may be large or sensitive
        super().__init__(f"bad args for {tool}: {detail}")

    def to_dict(self) -> dict:
        # Omit _raw from external-facing dict; include detail only.
        return {**super().to_dict(), "tool": self.tool, "detail": self.detail}


class UnknownToolError(FatalAgentError):
    """The model requested a tool name that is not registered."""

    def __init__(self, tool_name: str) -> None:
        self.tool_name = tool_name
        super().__init__(f"unknown tool: {tool_name!r}")


class BudgetExceededError(FatalAgentError):
    """The run exhausted its token or cost budget."""

    def __init__(self, spent: int, limit: int, unit: str = "tokens") -> None:
        self.spent = spent
        self.limit = limit
        self.unit = unit
        super().__init__(f"budget exceeded: {spent}/{limit} {unit}")

    def to_dict(self) -> dict:
        return {
            **super().to_dict(),
            "spent": self.spent,
            "limit": self.limit,
            "unit": self.unit,
        }


class ContextWindowError(FatalAgentError):
    """The conversation has grown too long to pass to the model."""

    def __init__(self, token_count: int) -> None:
        self.token_count = token_count
        super().__init__(f"context window exceeded: {token_count} tokens")

