import asyncio
from errors import (
    RecoverableAgentError, FatalAgentError, RateLimitError, AgentError
)

MAX_RETRIES = 4


async def run_with_retry(task: str) -> str:
    for attempt in range(MAX_RETRIES):
        try:
            return await agent_step(task)
        except RateLimitError as exc:
            # Use the server-supplied hint or exponential back-off.
            wait = exc.retry_after if exc.retry_after is not None else 2 ** attempt
            await asyncio.sleep(wait)
        except RecoverableAgentError:
            # Generic recoverable: brief back-off, then retry.
            if attempt == MAX_RETRIES - 1:
                raise
            await asyncio.sleep(0.5 * 2 ** attempt)
        except FatalAgentError:
            raise  # Never retry fatal errors — abort immediately.
    raise RuntimeError("exhausted retries without resolution")

from errors import (
    AgentError, ToolTimeoutError, ToolParseError,
    UnknownToolError, RateLimitError,
