def exc_to_tool_message(tool_call_id: str, exc: AgentError) -> dict:
    """Return an OpenAI tool-role message conveying why the tool failed."""
    if isinstance(exc, ToolTimeoutError):
        content = (
            f"Tool '{exc.tool}' timed out after {exc.timeout}s. "
            "Try a simpler or shorter query."
        )
    elif isinstance(exc, UnknownToolError):
        content = (
            f"Tool '{exc.tool_name}' is not registered. "
            "Available tools: web_search, calculator, file_read."
        )
    elif isinstance(exc, ToolParseError):
        content = f"Invalid arguments for '{exc.tool}': {exc.detail}"
    elif isinstance(exc, RateLimitError):
        suffix = f" (retry in {exc.retry_after}s)" if exc.retry_after else ""
        content = f"Rate limited by external API{suffix}. Pause before retrying."
    else:
        content = f"Tool failed: {exc}"

    return {
        "role": "tool",
        "tool_call_id": tool_call_id,
        "content": content,
    }


