from fastapi import FastAPI, Request
from fastapi.responses import JSONResponse
from errors import AgentError, RecoverableAgentError, FatalAgentError
import logging

log = logging.getLogger(__name__)
app = FastAPI()


@app.exception_handler(RateLimitError)
async def rate_limit_handler(request: Request, exc: RateLimitError):
    # Specific handler wins because it is registered first.
    body = exc.to_dict()
    body["retryable"] = True
    headers = {}
    if exc.retry_after is not None:
        headers["Retry-After"] = str(int(exc.retry_after))
    log.warning("rate limited", extra=exc.to_dict())
    return JSONResponse(status_code=429, content=body, headers=headers)


@app.exception_handler(RecoverableAgentError)
async def recoverable_handler(request: Request, exc: RecoverableAgentError):
    log.warning("recoverable agent error", extra=exc.to_dict())
    body = {**exc.to_dict(), "retryable": True}
    return JSONResponse(status_code=503, content=body)


@app.exception_handler(FatalAgentError)
async def fatal_handler(request: Request, exc: FatalAgentError):
    log.error("fatal agent error", extra=exc.to_dict())
    body = {**exc.to_dict(), "retryable": False}
    return JSONResponse(status_code=400, content=body)


@app.exception_handler(AgentError)
async def generic_agent_handler(request: Request, exc: AgentError):
    log.exception("unexpected agent error")
    return JSONResponse(status_code=500, content={"error": "internal error"})

