import asyncio
from errors import AgentError, RecoverableAgentError

async def fan_out_tools(calls: list[tuple[str, dict]]) -> list[dict | AgentError]:
    """Run all tool calls concurrently; collect results and errors separately."""
    tasks = [run_tool(name, args) for name, args in calls]
    results = await asyncio.gather(*tasks, return_exceptions=True)

    successes, errors = [], []
    for r in results:
        if isinstance(r, AgentError):
            errors.append(r)
        else:
            successes.append(r)

    if errors:
        # Log every error, then decide based on recoverable / fatal split.
        for exc in errors:
            log.warning("tool failed", **exc.to_dict())
        if any(not isinstance(e, RecoverableAgentError) for e in errors):
            raise errors[0]  # at least one fatal error — abort

    return successes

