class ToolParseError(RecoverableAgentError):
    def __init__(self, tool: str, detail: str, raw: str = "") -> None:
        self.tool = tool
        self.detail = detail
        self._raw = raw          # underscore: internal only

    def to_dict(self) -> dict:
        # Safe for clients: detail is structural, raw is omitted.
        return {
            "error_type": "ToolParseError",
            "tool": self.tool,
            "detail": self.detail,
        }

    def log_dict(self) -> dict:
        # Internal structured log: include excerpt for debugging.
